class GroqWhisperApi(
    private val client: OkHttpClient,
    private val rateLimiter: RateLimiter
) {
    suspend fun transcribeWithRetry(audioFile: File, maxRetries: Int = 3): TranscriptionResult {
        return withTimeoutOrNull(timeout) {
            repeat(maxRetries) { attempt ->
                try {
                    return@withTimeoutOrNull transcribe(audioFile)
                } catch (e: RateLimitExceededException) {
                    rateLimiter.waitForQuota()
                    if (attempt == maxRetries - 1) throw e
                }
            }
        } ?: throw TranscriptionTimeoutException()
    }
}
